mapper.select:
SELECT * FROM ( SELECT p.PRODUCT_ID, p.PRODUCT_NAME, p.SKU, p.BRAND, p.BASE_PRICE as PRICE, 0 as STOCK_QUANTITY, p.STATUS, p.CREATED_AT, p.UPDATED_AT, c.CATEGORY_NAME, 0 as TOTAL_SOLD, 0 as TOTAL_REVENUE, 0 as AVG_RATING, 0 as REVIEW_COUNT, ROW_NUMBER() OVER (ORDER BY p.CREATED_AT DESC) as RN FROM PRODUCTS p, CATEGORIES c WHERE p.CATEGORY_ID = c.CATEGORY_ID(+)
AND UPPER(p.PRODUCT_NAME) LIKE '%' || UPPER(#{productName}) || '%'
AND UPPER(p.BRAND) LIKE '%' || UPPER(#{brand}) || '%'
AND p.STATUS = #{status}
AND p.CATEGORY_ID = #{categoryId}
AND p.BASE_PRICE >= #{minPrice}
AND p.BASE_PRICE <= #{maxPrice}
)
WHERE ROWNUM <= #{offset} + #{limit} AND RN > #{offset}
ORDER BY RN

SELECT COUNT(*) as count
FROM PRODUCTS p
WHERE 1=1

    AND UPPER(p.PRODUCT_NAME) LIKE '%' || UPPER(#{productName}) || '%'


    AND UPPER(p.BRAND) LIKE '%' || UPPER(#{brand}) || '%'


    AND p.STATUS = #{status}


    AND p.CATEGORY_ID = #{categoryId}


     AND p.BASE_PRICE >= #{minPrice} 


     AND p.BASE_PRICE <= #{maxPrice}

mapper.update:

UPDATE PRODUCTS
SET UPDATED_AT = SYSDATE
WHERE PRODUCT_ID = #{productId}
